        svm_name = st.session_state.get('svm_name')

# ─────────────────────────────────────────────────────────────────────────────
# Contenido principal
# ─────────────────────────────────────────────────────────────────────────────
if tele_to_send and svm_to_send:
    if tele_name.endswith('.mat'):
        # 1. Cargar DataFrame (cacheado)
        df_local = get_mat_dataframe(tele_to_send)

        if df_local is not None and 'Lap_Number' in df_local.columns:
            laps = sorted([int(l) for l in df_local['Lap_Number'].unique() if l > 0])

            if laps:
                # 2. Pre-generar gráficos (cacheado como recurso)
                # La clave del cache es el hash del contenido del archivo y la lista de vueltas
                all_lap_figs = precompute_all_laps(df_local, tuple(laps))

                # Detectar vuelta rápida
                fastest_lap = None
                lap_times = {}
                # Preferir Last_Laptime (más preciso) sobre Session_Elapsed_Time
                has_last_laptime = 'Last_Laptime' in df_local.columns
                for l in laps:
                    lap_df_tmp = df_local[df_local['Lap_Number'] == l]
                    if not lap_df_tmp.empty:
                        if has_last_laptime:
                            lt = lap_df_tmp['Last_Laptime'].iloc[-1]
                            if lt > 0:
                                lap_times[l] = float(lt)
                                continue
                        # Fallback a Session_Elapsed_Time
                        if 'Session_Elapsed_Time' in df_local.columns:
                            lap_times[l] = float(lap_df_tmp['Session_Elapsed_Time'].max() - lap_df_tmp['Session_Elapsed_Time'].min())
                if lap_times:
                    fastest_lap = min(lap_times, key=lap_times.get)

                main_tab_tele, main_tab_setup, main_tab_ai = st.tabs(
                    [" Telemetría", " Setup", " Análisis AI"]
                )

                with main_tab_tele:
                    # Formatear tiempos de vuelta
                    def _fmt_lap_time(seconds):
                        m = int(seconds // 60)
                        s = seconds % 60
                        tenths = int(round((s % 1) * 10))
                        return f"{m}:{int(s):02}:{tenths}00"

                    lap_options = []
                    for l in laps:
                        t_str = ""
                        if l in lap_times:
                            t_val = _fmt_lap_time(lap_times[l])
                            t_str = f" ({t_val})"
                        lap_options.append(f"V{l}{t_str}")

                    plot_all_laps_interactive(all_lap_figs, laps, lap_options, fastest_lap)

                with main_tab_setup:
                    st.header("Configuración del Coche (.svm)")

                    # Inicializar estado temporal de edición si no existe
                    if 'temp_fixed_params' not in st.session_state:
                        st.session_state['temp_fixed_params'] = st.session_state['fixed_params'].copy()

                    def _clean_svm_value(val):
                        val_str = str(val)
                        if "//" in val_str:
                            parts = val_str.split("//", 1)
                            if len(parts) > 1:
                                return parts[1].strip()
                        return val_str.strip()

                    setup_data = parse_svm_content(svm_to_send)
                    # Cargar mapping para nombres amigables
                    _mapping_path = os.path.join(os.path.dirname(os.path.dirname(__file__)), "app", "core", "param_mapping.json")
                    _mapping = {"sections": {}, "parameters": {}}
                    if os.path.exists(_mapping_path):
                        try:
                            with open(_mapping_path, 'r', encoding='utf-8') as _mf:
                                _mapping = _json.load(_mf)
                        except Exception:
                            pass

                    # Formulario para agrupar cambios y evitar recargas por cada clic
                    with st.form("setup_fixed_params_form", border=False):
                        # Botón para guardar cambios arriba para accesibilidad
                        save_col1, save_col2 = st.columns([1.5, 3.5])
                        with save_col1:
                            submitted = st.form_submit_button(" Guardar parámetros fijados", use_container_width=True)
                        with save_col2:
                            st.info("Selecciona los parámetros que quieres fijar para que la IA sepa que no se tienen que modificar y pulsa el botón para guardar todos los cambios.", icon="ℹ️")

                        for section, params in setup_data.items():
                            if section.upper() in ("LEFTFENDER", "RIGHTFENDER"):
                                continue
                            friendly_section = _mapping.get("sections", {}).get(section, section)
                            with st.expander(f" {friendly_section}"):
                                rows = []
                                for k, v in params.items():
                                    if k.startswith("Gear") and "Setting" in k:
                                        continue
                                    friendly_param = _mapping.get("parameters", {}).get(k, k)
                                    if k in ("VehicleClassSetting", "UpgradeSetting"):
                                        continue

                                    if friendly_param.startswith("Ajuste de Chasis") or k.startswith("ChassisAdj"):
                                        continue

                                    clean_v = _clean_svm_value(v)
                                    if not clean_v:
                                        continue

                                    is_fixed = k in st.session_state['temp_fixed_params']
                                    rows.append({
                                        "Fijar": is_fixed,
                                        "Parámetro": friendly_param,
                                        "Valor": clean_v,
                                        "_internal_key": k
                                    })

                                if rows:
                                    # Guardar filas para referencia al procesar el formulario
                                    st.session_state[f"rows_{section}"] = rows
                                    df_setup = pd.DataFrame(rows)
                                    # editor sin on_change (se procesa al pulsar el botón del form)
                                    st.data_editor(
                                        df_setup,
                                        column_config={
                                            "Fijar": st.column_config.CheckboxColumn(
                                                "Fijar",
                                                help="Si se marca, la IA no cambiará este valor pero lo usará para el análisis",
                                                default=False,
                                            ),
                                            "Parámetro": st.column_config.TextColumn(disabled=True),
                                            "Valor": st.column_config.TextColumn(disabled=True),
                                            "_internal_key": None
                                        },
                                        disabled=["Parámetro", "Valor"],
                                        hide_index=True,
                                        key=f"editor_{section}",
                                    )

                        if submitted:
                            # Procesar todos los editores al enviar el formulario
                            new_fixed = st.session_state['fixed_params'].copy()

                            # Recorrer todas las secciones cargadas
                            for section in setup_data.keys():
                                editor_key = f"editor_{section}"
                                rows_key = f"rows_{section}"
                                if editor_key in st.session_state and rows_key in st.session_state:
                                    changes = st.session_state[editor_key]
                                    rows = st.session_state[rows_key]
                                    edited_rows = changes.get("edited_rows", {})

                                    # Actualizar basándose en los cambios manuales en el editor
                                    for idx_str, change in edited_rows.items():
                                        idx = int(idx_str)
                                        if idx < len(rows):
                                            internal_key = rows[idx]["_internal_key"]
                                            if "Fijar" in change:
                                                if change["Fijar"]:
                                                    new_fixed.add(internal_key)
                                                else:
                                                    new_fixed.discard(internal_key)

                            st.session_state['fixed_params'] = new_fixed
                            st.session_state['temp_fixed_params'] = new_fixed.copy()
                            if save_fixed_params(new_fixed):
                                st.success("¡Parámetros guardados correctamente!")
                                st.rerun()

                        # Si no hay filas en ninguna sección, mostrar mensaje
                        has_any_rows = any(len(params) > 0 for section, params in setup_data.items() if section.upper() not in ("LEFTFENDER", "RIGHTFENDER"))
                        if not has_any_rows:
                            st.caption("No hay parámetros configurados disponibles.")

                with main_tab_ai:
                    st.header("Análisis de Ingeniero Virtual")

                    try:
                        models_resp = requests.get(f"{API_BASE_URL}/models", timeout=2)
                        available_models = (
                            models_resp.json().get("models", [])
                            if models_resp.status_code == 200 else []
                        )
                    except Exception:
                        available_models = []

                    sel_model = st.selectbox("Modelo LLM", available_models) if available_models else None
                    analyze_button = st.button(" Iniciar Análisis con IA")

                    if analyze_button:
                        with st.spinner("Analizando con IA…"):
                            files = {
                                "telemetry_file": (tele_name, tele_to_send),
                                "svm_file": (svm_name, svm_to_send),
                            }
                            data_form = {}
                            if sel_model:
                                data_form["model"] = sel_model

                            # Enviar lista de parámetros fijados
                            if 'fixed_params' in st.session_state and st.session_state['fixed_params']:
                                data_form["fixed_params"] = _json.dumps(list(st.session_state['fixed_params']))

                            response = requests.post(
                                f"{API_BASE_URL}/analyze",
                                files=files, data=data_form
                            )
                            if response.status_code == 200:
                                data = response.json()
                                # Guardar datos en session_state para re-análisis
                                st.session_state['ai_analysis_data'] = data
                                st.session_state['ai_telemetry_summary'] = data.get('telemetry_summary_sent', '')
                                st.session_state['ai_circuit_name'] = tele_name.split('-')[-2].strip() if '-' in tele_name else "Desconocido"
                                st.session_state['ai_model'] = sel_model
                                # Parsear setup_data del .svm para re-análisis
                                st.session_state['ai_setup_data'] = parse_svm_content(svm_to_send)
                            else:
                                st.error("Error en el análisis.")

                    # Mostrar resultados (persistentes en session_state)
                    if 'ai_analysis_data' in st.session_state:
                        data = st.session_state['ai_analysis_data']

                        # ── Análisis del Ingeniero de Conducción ──
                        st.subheader(" Análisis del Ingeniero de Conducción")
                        st.info(data['driving_analysis'])

                        # ── Razonamiento del Ingeniero Jefe ──
                        if data.get('chief_reasoning'):
                            st.subheader(" Razonamiento del Ingeniero Jefe")
                            st.warning(data['chief_reasoning'])

                        # ── Setup Completo Recomendado ──
                        if data.get('full_setup') and data['full_setup'].get('sections'):
                            st.subheader("⚙️ Setup Completo Recomendado por los ingenieros")
                            for sec_idx, section in enumerate(data['full_setup']['sections']):
                                s_name = section.get('name', 'Sección')
                                s_key = section.get('section_key', '')
                                s_items = section.get('items', [])
                                if not s_items:
                                    continue
                                changed_items = [it for it in s_items if str(it.get('current', '')) != str(it.get('new', ''))]
                                with st.expander(f" {s_name} ({len(changed_items)} cambios)", expanded=bool(changed_items)):
                                    if changed_items:
                                        rows = []
                                        for it in changed_items:
                                            param_name = it.get('parameter', '')
                                            if it.get('reanalyzed'):
                                                param_name = f" {param_name}"
                                            rows.append({
                                                "Parámetro": param_name,
                                                "Actual": it.get('current', ''),
                                                "Recomendado": it.get('new', ''),
                                                "Motivo": it.get('reason', '')
                                            })
                                        df_ai = pd.DataFrame(rows)
                                        st.table(df_ai.set_index("Parámetro"))
                                    else:
                                        st.caption("No se recomiendan cambios en esta sección.")
            else:
                st.warning("No se encontraron vueltas completas.")
        else:
            st.error("No se encontró canal 'Lap_Number' en el .mat")
    else:
        st.info("La visualización detallada actualmente solo soporta archivos .mat.")
        if st.button("Analizar con IA"):
            with st.spinner("Analizando con IA…"):
                files = {
                    "telemetry_file": (tele_name, tele_to_send),
                    "svm_file": (svm_name, svm_to_send),
                }
                response = requests.post(f"{API_BASE_URL}/analyze", files=files)
                if response.status_code == 200:
                    data = response.json()
                    st.success("Análisis completado")
                    st.write(data['driving_analysis'])
                else:
                    st.error("Error en el análisis.")
else:
    st.info(" Sube tus archivos o elige una sesión anterior en la barra lateral para comenzar.")

"""
Script para crear las tareas de Asana para la fase:
  Mapa con gradiente freno/acelerador + filtro telemetría conducción
Usa el token MCP renovado.
"""
import json
import os
import requests

TOKEN_FILE = os.path.join(os.environ["APPDATA"], "asana-mcp", "token.json")
ENDPOINT = "https://mcp.asana.com/v2/mcp"

with open(TOKEN_FILE) as f:
    token_data = json.load(f)
ACCESS_TOKEN = token_data["access_token"]


def mcp_request(method, params=None, session_id=None, req_id=1):
    headers = {
        "Authorization": f"Bearer {ACCESS_TOKEN}",
        "Content-Type": "application/json",
        "Accept": "application/json, text/event-stream",
    }
    if session_id:
        headers["Mcp-Session-Id"] = session_id
    payload = {"jsonrpc": "2.0", "id": req_id, "method": method}
    if params is not None:
        payload["params"] = params
    return requests.post(ENDPOINT, headers=headers, json=payload)


def parse_resp(resp):
    ct = resp.headers.get("Content-Type", "")
    if "text/event-stream" in ct:
        for line in resp.text.splitlines():
            if line.startswith("data:"):
                data_str = line[5:].strip()
                if data_str:
                    try:
                        return json.loads(data_str)
                    except Exception:
                        continue
        return None
    try:
        return resp.json()
    except Exception:
        return None


def call_tool(session_id, tool_name, arguments, req_id=1):
    r = mcp_request("tools/call", {"name": tool_name, "arguments": arguments},
                    session_id=session_id, req_id=req_id)
    result = parse_resp(r)
    if result and "result" in result:
        content = result["result"].get("content", [])
        for item in content:
            if item.get("type") == "text":
                try:
                    return json.loads(item["text"])
                except Exception:
                    return item["text"]
    if result and "error" in result:
        print(f"  ERROR: {result['error']}")
    return None


def main():
    # 1. Inicializar sesión MCP
    r = mcp_request("initialize", {
        "protocolVersion": "2024-11-05",
        "capabilities": {},
        "clientInfo": {"name": "copilot-script", "version": "1.0"},
    })
    result = parse_resp(r)
    session_id = r.headers.get("Mcp-Session-Id")
    print(f"Session: {session_id}")

    # 2. Notification initialized
    headers = {
        "Authorization": f"Bearer {ACCESS_TOKEN}",
        "Content-Type": "application/json",
        "Accept": "application/json, text/event-stream",
        "Mcp-Session-Id": session_id,
    }
    requests.post(ENDPOINT, headers=headers,
                  json={"jsonrpc": "2.0", "method": "notifications/initialized"})

    # 3. Obtener usuario actual
    me = call_tool(session_id, "get_me", {}, req_id=2)
    print(f"Usuario: {me}")

    # 4. Buscar o usar proyecto rFactor2 Engineer ya existente
    projects = call_tool(session_id, "get_projects", {}, req_id=3)
    print(f"Proyectos: {json.dumps(projects, indent=2)[:500]}")

    existing_project = None
    if projects and "data" in projects:
        for p in projects["data"]:
            if "rfactor" in p.get("name", "").lower() or "engineer" in p.get("name", "").lower():
                existing_project = p
                break

    if existing_project:
        project_gid = existing_project["gid"]
        print(f"Proyecto encontrado: {existing_project['name']} (GID: {project_gid})")
    else:
        # Crear proyecto
        new_proj = call_tool(session_id, "create_project", {
            "name": "rFactor2 Engineer",
            "notes": "Proyecto de desarrollo de la app rFactor2 Engineer - análisis de telemetría y setup con IA.",
            "color": "dark-red",
            "default_view": "list",
        }, req_id=4)
        print(f"Proyecto creado: {json.dumps(new_proj, indent=2)[:300]}")
        # create_project devuelve el objeto directamente (sin wrapper "data")
        if isinstance(new_proj, dict) and "gid" in new_proj:
            project_gid = new_proj["gid"]
        else:
            project_gid = new_proj["data"]["gid"]

    print(f"\nUsando proyecto GID: {project_gid}")

    # 5. Crear Tarea A (sin dependencias)
    task_a_data = call_tool(session_id, "create_tasks", {
        "default_project": project_gid,
        "tasks": [
            {
                "name": "[Fase: Mapa+Driving] Tarea A: Mapa con gradiente freno/acelerador",
                "notes": (
                    "Implementar coloreado por tramos en el mapa del circuito.\n\n"
                    "Descripción:\n"
                    "- Añadir arrays `raw_lon`, `raw_lat`, `brake` (0-100%) y `throttle` (0-100%) "
                    "a `data['map']` en `_build_lap_data()` (frontend/streamlit_app.py)\n"
                    "- Reemplazar el renderizado del mapa JS: 3 trazas Plotly:\n"
                    "  * Traza 0: línea gris de fondo (circuito completo)\n"
                    "  * Traza 1: marcadores coloreados (brake=rojo, throttle=azul, ambos=mezcla morada)\n"
                    "  * Traza 2: marcador de posición del coche\n"
                    "- Gradiente: 0%=blanco, 100%=rojo pleno (#FF0000) para freno / azul pleno (#0000FF) para acelerador\n"
                    "- Si brake Y throttle activos simultáneamente: mezcla rgb(255-t, 255-b-t, 255-b) → morado\n"
                    "- Solo mostrar tramos activos (sin color para coast)\n"
                    "- Actualizar Plotly.restyle de posición del coche de traza [1] a [2]\n"
                    "- Añadir unit tests para `_build_lap_data()` en tests/\n\n"
                    "Archivos: frontend/streamlit_app.py, tests/\n"
                    "Fase: Mapa+Driving\n"
                    "Depende de: ninguna"
                ),
            }
        ],
    }, req_id=5)
    print(f"\nTarea A creada: {json.dumps(task_a_data, indent=2)[:400]}")
    task_a_gid = task_a_data["succeeded"][0]["gid"]
    print(f"Tarea A GID: {task_a_gid}")

    # 6. Crear Tarea B (sin dependencias — paralela a A)
    task_b_data = call_tool(session_id, "create_tasks", {
        "default_project": project_gid,
        "tasks": [
            {
                "name": "[Fase: Mapa+Driving] Tarea B: Filtro telemetría agente de conducción",
                "notes": (
                    "Restringir la telemetría enviada al agente de conducción a canales de técnica de pilotaje.\n\n"
                    "Descripción:\n"
                    "- En app/main.py: construir `driving_csv_for_ai` filtrado a columnas: "
                    "`Lap Number`, `Lap Distance`, `Throttle Pos`, `Brake Pos`, `Steering`, `Engine RPM`, `Gear`\n"
                    "- Construir `driving_summary` (mismo formato que `summary` pero con CSV filtrado)\n"
                    "- Pasar `driving_telemetry_summary=driving_summary` a `ai_engineer.analyze()`\n"
                    "- En app/core/ai_agents.py: añadir parámetro `driving_telemetry_summary=None` a `analyze()`\n"
                    "- Usar `driving_telemetry_summary or telemetry_summary` al invocar el DRIVING_PROMPT\n"
                    "- Actualizar tests: tests/core/test_ai_agents.py y tests/test_main.py\n\n"
                    "Archivos: app/main.py, app/core/ai_agents.py, tests/core/test_ai_agents.py, tests/test_main.py\n"
                    "Fase: Mapa+Driving\n"
                    "Depende de: ninguna"
                ),
            }
        ],
    }, req_id=6)
    print(f"\nTarea B creada: {json.dumps(task_b_data, indent=2)[:400]}")
    task_b_gid = task_b_data["succeeded"][0]["gid"]
    print(f"Tarea B GID: {task_b_gid}")

    # 7. Crear Tarea C: Validación final (depende de A y B)
    task_c_data = call_tool(session_id, "create_tasks", {
        "default_project": project_gid,
        "tasks": [
            {
                "name": "[Fase: Mapa+Driving] Tarea C: Suite de tests verde + RC tag",
                "notes": (
                    "Validación final de la fase tras merge de Tarea A y Tarea B.\n\n"
                    "Descripción:\n"
                    "- Ejecutar suite completa: `pytest tests/ --ignore=tests/integration -v`\n"
                    "- Ejecutar ruff: `python -m ruff check app/ frontend/ tests/`\n"
                    "- Corregir cualquier fallo de lint o test\n"
                    "- Taggear Release Candidate en develop: `git tag v0.X.0-rc.1`\n"
                    "- Actualizar estado del proyecto Asana: 'Phase complete — RC tagged'\n\n"
                    "Archivos: ninguno propio (solo validación)\n"
                    "Fase: Mapa+Driving\n"
                    f"Depende de: Tarea A ({task_a_gid}), Tarea B ({task_b_gid})"
                ),
            }
        ],
    }, req_id=7)
    print(f"\nTarea C creada: {json.dumps(task_c_data, indent=2)[:400]}")
    task_c_gid = task_c_data["succeeded"][0]["gid"]

    # 8. Establecer dependencias de C → A y C → B
    dep_result = call_tool(session_id, "update_tasks", {
        "tasks": [
            {
                "task": task_c_gid,
                "add_dependencies": [task_a_gid, task_b_gid],
            }
        ]
    }, req_id=8)
    print(f"\nDependencias Tarea C establecidas: {json.dumps(dep_result, indent=2)[:300]}")

    # 9. Estado inicial: A y B → In Progress (ambas en la ready frontier)
    # Añadir comentario de inicio en A y B
    comment_a = call_tool(session_id, "add_comment", {
        "task_id": task_a_gid,
        "text": "Assigned to subagent. Starting implementation of gradient map coloring.",
    }, req_id=9)
    comment_b = call_tool(session_id, "add_comment", {
        "task_id": task_b_gid,
        "text": "Assigned to subagent. Starting implementation of driving telemetry filter.",
    }, req_id=10)
    print(f"\nComentarios de inicio añadidos.")

    print("\n" + "="*60)
    print("RESUMEN DE TAREAS CREADAS:")
    print(f"  Proyecto GID : {project_gid}")
    print(f"  Tarea A GID  : {task_a_gid}  (Mapa gradiente — sin deps)")
    print(f"  Tarea B GID  : {task_b_gid}  (Filtro telemetría — sin deps)")
    print(f"  Tarea C GID  : {task_c_gid}  (Validación — depende de A+B)")
    print("="*60)


if __name__ == "__main__":
    main()
